import { Link, useLocation } from 'react-router-dom';
import { useState, useEffect } from 'react';

export default function Header() {
  const location = useLocation();
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const isHomePage = location.pathname === '/';


  return (
     <header className="bg-gradient-to-r from-gray-700 to-gray-800 text-white py-4 sticky top-0 z-50 shadow-2xl border-b-2 border-gray-900">
        <div className="container mx-auto px-2">
          <div className="flex flex-col lg:flex-row items-center justify-between space-y-4 lg:space-y-0">
            <div className="flex items-center space-x-4 slide-in-left">
              <div className="w-12 h-12 bg-white/20 rounded-xl flex items-center justify-center shadow-lg">
                <i className="fas fa-bolt text-2xl text-white"></i>
              </div>
              <div>
                <div className="hidden lg:block">
                  <h1 className="text-lg font-semibold text-white">Devis décennale{' '}
                    Electricien en quelques clics</h1>
                </div>
                <div className="lg:hidden">
                  <h1 className="text-sm font-semibold text-white">Décennale</h1>
                  <p className="text-xs text-white/80">Electricien</p>
                </div>
              </div>
            </div>

            <div className="flex items-center space-x-4 slide-in-right">
              <div className="p-4 bg-white/20 rounded-2xl icon-bounce shadow-lg">
                <i className="fas fa-phone text-2xl text-white"></i>
              </div>
              <div>
                <span className="text-sm text-white/80 block">Conseil personnalisé</span>
                <a href="tel:0182834800" className="text-2xl font-bold text-white hover:text-gray-200 transition-colors duration-300">
                  01 82 83 48 00</a>
              </div>
            </div>
          </div>
        </div>
      </header>
  );
}
